var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"결국 운명의 끝은 정해져 있는 거야. 아디트야.","JPN":"結局運命の果ては定められているのだ。アーディティヤ。","ENG":"The end of fate is decided in the end, Aditya.","TWN":"你的最終命運是註定的，阿迪亞。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"당신은 숭고한 임무를 져버리고 도망쳤습니다.","JPN":"あなたは崇高な任務を見捨て、逃げました。","ENG":"You have abandoned your noble mission and fled.","TWN":"你放棄崇高的任務落荒而逃。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_SHADOW_NULL","text":{"KOREA":"하지만 아직 약속을 지킬 수 있어. 아주 간단한 방법이지.","JPN":"でもまだ約束は守れる。とても簡単な方法だ。","ENG":"But you can still keep your promise. We can offer you a simple solution.","TWN":"但你還能遵守約定，有個非常簡單的方法。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"하지만 아직 당신에게 구원의 손길이 남아 있습니다.","JPN":"ですが、まだあなたに救いの道は残っています。","ENG":"There is still salvation for you.","TWN":"你還有救贖的機會。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"어서.","JPN":"早く。","ENG":"Go.","TWN":"來。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"어서.","JPN":"早く。","ENG":"Go.","TWN":"來。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"<color=#ff3636>우리를 완성하도록 해요. </color>","JPN":"<color=#ff3636>私たちを完成してください。</color>","ENG":"<color=#ff3636>Go complete us.</color>","TWN":"<color=#ff3636>讓我們完整吧。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"환각이 점점 강해지고 있다.","JPN":"どんどん幻覚がひどくなっている。","ENG":"The hallucinations are getting worse.","TWN":"幻覺越來越嚴重了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식파의 영향인가? 워치의 초침도 이제 곧 한계야.","JPN":"侵食波の影響か？　ウォッチの針ももうすぐ限界だ。","ENG":"Is it the effect of the Corruption rays? The Watch's second hand will soon reach its limit.","TWN":"是侵蝕波的影響嗎？能量環也快到極限了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇다면…… 적어도 너 하나는 반드시…….","JPN":"ならば……少なくとも君だけは必ず……","ENG":"Then... I must at least...","TWN":"那……至少要和你一起……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"힘이 내 몸을 불태울 만큼 폭주하기 시작하고.","JPN":"力が自分の体を燃え尽くすほどに暴走し始め。","ENG":"The power started to run rampant, enough to burn my body.","TWN":"足以燃燒我身體的力量開始暴走。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"녀석은 그 모습을 보곤 황홀한 듯 입을 쩍 벌린 채 굶주린 짐승처럼 다가온다.","JPN":"やつはその姿を見てうっとりとしたように口を大きく開けては飢えた獣のごとく近づいてくる。","ENG":"The thing sees me and starts approaching me with its mouth open in raptus like a starving beast.","TWN":"那個傢伙張大嘴巴，像饑餓的野獸一樣靠近。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"나를 향한 망집. 침식체는 제 몸이 모두 불타더라도 단 하나의 욕망을 위해 움직인다.","JPN":"私への妄執。侵食体は自分の身が燃え尽きようと、ただ一つの欲望のために動く。","ENG":"Its obsession headed toward me. The C.O. moves for its one desire, even if it means setting its entire body on fire.","TWN":"那是對於我的妄念。即使吞下焚身的烈焰，它也會為唯一的欲望而行動。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"인도하는 태양과 영원히 함께하는 것.","JPN":"導く太陽と永遠に共にすること。","ENG":"To be with the guiding sun forever.","TWN":"就是與引導之陽永遠相伴。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"자, 입을 벌려라. 바루나스트라.","JPN":"さあ、口を開けろ。ヴァルナストラ。","ENG":"Now, open wide, Varunastra.","TWN":"來，再張大些，伐樓拿之艦。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 모든 가능성을 연료 삼아 너의 모든 것을 불태워주겠다.","JPN":"私のすべての可能性を燃料にし、君のすべてを燃え尽くしてやろう。","ENG":"I will use all my possibilities as fuel to set you on fire.","TWN":"用我所有的可能性作為燃料，燃燒你的一切。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"탐욕스러운 고래가 나를 향해 입을 벌렸을 때.","JPN":"貪欲なクジラが私に向かって口を開けた瞬間、","ENG":"When the greedy whale opened its mouth toward me.","TWN":"貪婪的鯨魚向我張開嘴巴。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히 내 모습이 과거에 머물러 있음을 깨달았다.","JPN":"私は自分の姿が今でも過去に留まっているということに気付いた。","ENG":"I realized that I was still stuck in the past.","TWN":"我意識到自己依然被困在過去。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"더 이상 잃을 것이 없는 내가 기꺼이 내놓을 수 있는 것은.","JPN":"もう失うものなどない私が喜んで差し出せるものは、","ENG":"All that I could gladly offer, after having nothing more to lose.","TWN":"只不過這一次，我已經沒有什麼可以失去。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"여전히, 그저 불타 없어질 목숨뿐이란 것을.","JPN":"相変わらず、ただ燃えて無くなる命だけだということに。","ENG":"That was still my life that will burn to ashes.","TWN":"能獻的，只有會燃燒殆盡的生命而已。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};